#include <bits/stdc++.h>
#define zrq0331
#define int long long
#define maxn 1000010
using namespace std;
int n,m;
int a[maxn],ans[maxn];
int vis[maxn],tree[maxn];
struct Edge {
	int l, r, id;
}q[maxn];
bool cmp (const Edge &a, const Edge &b){
	return a.r < b.r;
}
int lowbit (int x) {
	return x & (-x);
}
void update (int i, int k) {
	for (; i <= n; i += lowbit (i)) {
		tree[i] += k;
	}
}
int getsum (int i) {
	int res = 0;
	for (; i; i -= lowbit (i)) {
		res += tree[i];
	}
	return res;
}
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	cin >> m;
	for (int i = 1; i <= m; i++){
		cin >> q[i].l;
		cin >> q[i].r;
		q[i].id=i;
	}
	sort (q + 1, q + m + 1, cmp);
	int pow = 1;
	for (int i = 1; i <= m; i++){
		for (int j = pow; j <= q[i].r; j++){
			if (vis[a[j]]) {
				update (vis[a[j]], -1);
			}
			update (j, 1);
			vis[a[j]] = j;
		}
		pow = q[i].r + 1;
		ans[q[i].id] = getsum (q[i].r) - getsum(q[i].l - 1);
	}
	for (int i = 1; i <= m; i++) {
		cout << ans[i] << '\n';
	}
	return 0;
}
